import java.util.HashMap;
import java.util.Map;

public class Main {
    static Map<Integer, Integer> memo = new HashMap<>();

    static int fibMemo(int n) {
        if (n <= 1) {
            return n;
        }
        if (memo.containsKey(n)) {
            return memo.get(n);
        }

        int result = fibMemo(n - 1) + fibMemo(n - 2);
        memo.put(n, result);
        return result;
    }

    public static void main(String[] args) {
        System.out.println(fibMemo(6));
        System.out.println(fibMemo(30));
    }
}

import java.util.ArrayList;
import java.util.List;

public class Main {
    static void generateSubsets(int[] nums, int index, List<Integer> current, List<List<Integer>> result) {
        if (index == nums.length) {
            result.add(new ArrayList<>(current));
            return;
        }

        // Choice 1: don't include nums[index]
        generateSubsets(nums, index + 1, current, result);

        // Choice 2: include nums[index]
        current.add(nums[index]);
        generateSubsets(nums, index + 1, current, result);
        current.remove(current.size() - 1); // undo the choice
    }

    public static void main(String[] args) {
        int[] nums = {1, 2};
        List<List<Integer>> result = new ArrayList<>();
        generateSubsets(nums, 0, new ArrayList<>(), result);
        System.out.println(result);
    }
}

