}

class Solution {
    public ListNode mergeTwoLists(ListNode list1, ListNode list2) {
        if (list1 == null) return list2; // base case
        if (list2 == null) return list1; // base case

        if (list1.val <= list2.val) {
            list1.next = mergeTwoLists(list1.next, list2);
            return list1;
        } else {
            list2.next = mergeTwoLists(list1, list2.next);
            return list2;
        }
    }
}

class Solution {
    public int kthGrammar(int n, int k) {
        String row = "0";
        for (int i = 2; i <= n; i++) {
            StringBuilder next = new StringBuilder();
            for (char c : row.toCharArray()) {
                next.append(c == '0' ? "01" : "10");
            }
            row = next.toString();
        }
        return row.charAt(k - 1) - '0';
    }
}

class Solution {
    public int kthGrammar(int n, int k) {
        if (n == 1) return 0; // base case -- row 1 is always "0"

        int parent = kthGrammar(n - 1, (k + 1) / 2);
        boolean isSecondHalf = (k % 2 == 0);

        if (parent == 0) {
            return isSecondHalf ? 1 : 0; // "0" becomes "01"
        } else {
            return isSecondHalf ? 0 : 1; // "1" becomes "10"
        }
    }
}

